import React, { useState, useEffect } from 'react';
import { useParams, Link } from 'react-router-dom';
import { companyService, newsService } from '../services/api';
import { Chart as ChartJS, CategoryScale, LinearScale, PointElement, LineElement, Title, Tooltip, Legend } from 'chart.js';
import { Line } from 'react-chartjs-2';
import './CompanyDetailPage.css';

// Register Chart.js components
ChartJS.register(CategoryScale, LinearScale, PointElement, LineElement, Title, Tooltip, Legend);

function CompanyDetailPage() {
  const { id } = useParams();
  const [company, setCompany] = useState(null);
  const [marketData, setMarketData] = useState(null);
  const [reports, setReports] = useState([]);
  const [shareholders, setShareholders] = useState([]);
  const [historicalData, setHistoricalData] = useState([]);
  const [news, setNews] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [activeTab, setActiveTab] = useState('overview');

  useEffect(() => {
    const fetchData = async () => {
      try {
        // Fetch basic company info first
        const companyResponse = await companyService.getCompany(id);
        setCompany(companyResponse.data);
        
        // Then fetch all other data in parallel
        const [marketResponse, reportsResponse, shareholdersResponse, historicalResponse] = 
          await Promise.all([
            companyService.getCompanyMarketData(id),
            companyService.getCompanyReports(id),
            companyService.getCompanyShareholders(id),
            companyService.getCompanyHistoricalData(id)
          ]);
        
        setMarketData(marketResponse.data);
        setReports(reportsResponse.data);
        setShareholders(shareholdersResponse.data);
        setHistoricalData(historicalResponse.data);
        
        // Fetch news related to this company
        if (company?.name) {
          const newsResponse = await newsService.searchCompanyNews(company.name);
          setNews(newsResponse.data);
        }
        
        setLoading(false);
      } catch (err) {
        console.error('Error fetching company data:', err);
        setError('خطا در دریافت اطلاعات شرکت. لطفاً دوباره تلاش کنید.');
        setLoading(false);
      }
    };

    fetchData();
  }, [id, company?.name]);

  const renderPriceChart = () => {
    if (!historicalData || historicalData.length === 0) {
      return <p>داده‌ای برای نمایش نمودار وجود ندارد.</p>;
    }

    // Format data for Chart.js
    const chartData = {
      labels: historicalData.map(item => item.date),
      datasets: [
        {
          label: 'قیمت پایانی',
          data: historicalData.map(item => item.close),
          borderColor: '#4299e1',
          backgroundColor: 'rgba(66, 153, 225, 0.5)',
        },
      ],
    };

    const options = {
      responsive: true,
      plugins: {
        legend: {
          position: 'top',
        },
        title: {
          display: true,
          text: 'نمودار قیمت',
        },
      },
    };

    return <Line options={options} data={chartData} />;
  };

  if (loading) {
    return (
      <div className="loading-container">
        <div className="loading-spinner"></div>
        <p>در حال بارگذاری...</p>
      </div>
    );
  }

  if (error) {
    return (
      <div className="error-container">
        <p className="error-message">{error}</p>
        <Link to="/dashboard" className="btn btn-primary">
          بازگشت به داشبورد
        </Link>
      </div>
    );
  }

  if (!company) {
    return (
      <div className="error-container">
        <p className="error-message">شرکت مورد نظر یافت نشد.</p>
        <Link to="/dashboard" className="btn btn-primary">
          بازگشت به داشبورد
        </Link>
      </div>
    );
  }

  return (
    <div className="company-detail-page">
      <div className="company-header">
        <h1>{company.name}</h1>
        <div className="company-symbol">{company.symbol}</div>
        
        {marketData && (
          <div className="market-summary">
            <div className="market-item">
              <span className="label">آخرین قیمت:</span>
              <span className="value">{marketData.lastPrice}</span>
            </div>
            <div className="market-item">
              <span className="label">تغییر:</span>
              <span className={`value ${parseFloat(marketData.change) >= 0 ? 'positive' : 'negative'}`}>
                {marketData.change}
              </span>
            </div>
            <div className="market-item">
              <span className="label">حجم معاملات:</span>
              <span className="value">{marketData.volume}</span>
            </div>
          </div>
        )}
      </div>
      
      <div className="company-tabs">
        <button 
          className={`tab-button ${activeTab === 'overview' ? 'active' : ''}`}
          onClick={() => setActiveTab('overview')}
        >
          نمای کلی
        </button>
        <button 
          className={`tab-button ${activeTab === 'reports' ? 'active' : ''}`}
          onClick={() => setActiveTab('reports')}
        >
          گزارش‌های مالی
        </button>
        <button 
          className={`tab-button ${activeTab === 'shareholders' ? 'active' : ''}`}
          onClick={() => setActiveTab('shareholders')}
        >
          سهامداران
        </button>
        <button 
          className={`tab-button ${activeTab === 'news' ? 'active' : ''}`}
          onClick={() => setActiveTab('news')}
        >
          اخبار
        </button>
      </div>
      
      <div className="company-content">
        {activeTab === 'overview' && (
          <div className="tab-content">
            <h2>نمای کلی</h2>
            <div className="chart-container">
              {renderPriceChart()}
            </div>
            
            {marketData && (
              <div className="market-details">
                <h3>اطلاعات بازار</h3>
                <div className="market-grid">
                  <div className="market-detail-item">
                    <span className="label">قیمت پایانی:</span>
                    <span className="value">{marketData.lastPrice}</span>
                  </div>
                  <div className="market-detail-item">
                    <span className="label">بیشترین قیمت:</span>
                    <span className="value">{marketData.highPrice}</span>
                  </div>
                  <div className="market-detail-item">
                    <span className="label">کمترین قیمت:</span>
                    <span className="value">{marketData.lowPrice}</span>
                  </div>
                  <div className="market-detail-item">
                    <span className="label">قیمت باز شدن:</span>
                    <span className="value">{marketData.openPrice}</span>
                  </div>
                  <div className="market-detail-item">
                    <span className="label">قیمت روز قبل:</span>
                    <span className="value">{marketData.yesterdayPrice}</span>
                  </div>
                  <div className="market-detail-item">
                    <span className="label">حجم معاملات:</span>
                    <span className="value">{marketData.volume}</span>
                  </div>
                  <div className="market-detail-item">
                    <span className="label">ارزش معاملات:</span>
                    <span className="value">{marketData.value}</span>
                  </div>
                </div>
              </div>
            )}
          </div>
        )}
        
        {activeTab === 'reports' && (
          <div className="tab-content">
            <h2>گزارش‌های مالی</h2>
            {reports && reports.length > 0 ? (
              <div className="reports-list">
                {reports.map((report, index) => (
                  <div key={index} className="report-item">
                    <h3>{report.title}</h3>
                    <p className="report-date">{report.date}</p>
                    {report.url && (
                      <a 
                        href={report.url} 
                        target="_blank" 
                        rel="noopener noreferrer"
                        className="report-link"
                      >
                        مشاهده گزارش
                      </a>
                    )}
                  </div>
                ))}
              </div>
            ) : (
              <p className="no-data">گزارشی یافت نشد.</p>
            )}
          </div>
        )}
        
        {activeTab === 'shareholders' && (
          <div className="tab-content">
            <h2>ترکیب سهامداران</h2>
            {shareholders && shareholders.length > 0 ? (
              <div className="shareholders-table">
                <div className="table-header">
                  <div className="header-cell">نام سهامدار</div>
                  <div className="header-cell">درصد مالکیت</div>
                  <div className="header-cell">تعداد سهام</div>
                </div>
                {shareholders.map((shareholder, index) => (
                  <div key={index} className="table-row">
                    <div className="table-cell">{shareholder.name}</div>
                    <div className="table-cell">{shareholder.percentage}</div>
                    <div className="table-cell">{shareholder.count}</div>
                  </div>
                ))}
              </div>
            ) : (
              <p className="no-data">اطلاعات سهامداران یافت نشد.</p>
            )}
          </div>
        )}
        
        {activeTab === 'news' && (
          <div className="tab-content">
            <h2>اخبار مرتبط</h2>
            {news && news.length > 0 ? (
              <div className="news-list">
                {news.map((item, index) => (
                  <div key={index} className="news-item">
                    <h3>{item.title}</h3>
                    <p className="news-date">{item.date}</p>
                    <p className="news-summary">{item.summary}</p>
                    {item.url && (
                      <a 
                        href={item.url} 
                        target="_blank" 
                        rel="noopener noreferrer"
                        className="news-link"
                      >
                        ادامه مطلب
                      </a>
                    )}
                  </div>
                ))}
              </div>
            ) : (
              <p className="no-data">خبری یافت نشد.</p>
            )}
          </div>
        )}
      </div>
      
      <div className="action-buttons">
        <Link to="/dashboard" className="btn btn-secondary">
          بازگشت به داشبورد
        </Link>
      </div>
    </div>
  );
}

export default CompanyDetailPage;
